         <html lang="en">
         <head>
            <meta charset="UTF-8">
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <title>Counter Widget</title>
            <link href="https://cdn.tailwindcss.com" rel="stylesheet">
         </head>
         <body>
            <div class="container mx-auto p-4">
               <div class="flex justify-center mt-4">
                  <button id="increment" class="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded" onclick="increment()">Increment</button>
                  <span id="counter" class="ml-4 mr-4"></span>
                  <button id="decrement" class="bg-red-500 hover:bg-red-700 text-white font-bold py-2 px-4 rounded" onclick="decrement()">Decrement</button>
               </div>
            </div>

            <script>
               let counter = 0;
               document.getElementById('counter').textContent = counter;

               function increment() {
                  counter++;
                  document.getElementById('counter').textContent = counter;
               }

               function decrement() {
                  counter--;
                  document.getElementById('counter').textContent = counter;
               }
            </script>
         </body>
         </html>

